#include <cuda_runtime.h>
#include <cstddef>

// CUDA kernel to compute a partial histogram over characters in the range [from, to].
// Each block builds a histogram in shared memory to reduce global atomic contention,
// then the per-block histograms are accumulated into the global histogram.
__global__ void histogram_kernel(const char *__restrict__ input,
                                 unsigned int *__restrict__ globalHist,
                                 unsigned int inputSize,
                                 int from,
                                 int to)
{
    extern __shared__ unsigned int sharedHist[];

    const int range = to - from + 1;  // Number of histogram bins (inclusive range [from, to])

    // Initialize shared-memory histogram to zero.
    // All threads in the block cooperate to zero the 'range' bins.
    for (int i = threadIdx.x; i < range; i += blockDim.x) {
        sharedHist[i] = 0u;
    }
    __syncthreads();

    const unsigned int tid = blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned int totalThreads = blockDim.x * gridDim.x;

    // Grid-stride loop so the kernel can handle arbitrarily large input.
    for (unsigned int idx = tid; idx < inputSize; idx += totalThreads) {
        // Cast to unsigned char to avoid sign-extension issues with 'char'.
        unsigned char c = static_cast<unsigned char>(input[idx]);

        // Map character code to bin index relative to 'from'.
        // Using a single subtraction avoids two comparisons against 'from' and 'to'.
        int bin = static_cast<int>(c) - from;

        // Only count characters within [from, to].
        if (bin >= 0 && bin < range) {
            // Shared-memory atomic is much faster than a global atomic.
            atomicAdd(&sharedHist[bin], 1u);
        }
    }

    __syncthreads();

    // Accumulate per-block shared histogram into the global histogram.
    // Each block updates each bin at most once, so global atomics are minimal.
    for (int i = threadIdx.x; i < range; i += blockDim.x) {
        unsigned int count = sharedHist[i];
        if (count != 0u) {
            atomicAdd(&globalHist[i], count);
        }
    }
}

// Host function that sets up and launches the histogram kernel.
//
// Parameters:
//   input      - device pointer to input text buffer (allocated with cudaMalloc)
//   histogram  - device pointer to histogram buffer of size (to - from + 1) unsigned ints
//   inputSize  - number of characters in 'input'
//   from, to   - inclusive character range [from, to] to histogram (0 <= from < to <= 255)
//
// Notes:
//   - This function zeroes the device-side histogram before launching the kernel.
//   - No host-device synchronization is performed here; the caller is responsible
//     for synchronizing and copying the histogram back to host memory if needed.
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Assumes input arguments satisfy 0 <= from < to <= 255.
    const int range = to - from + 1;
    if (range <= 0) {
        // Invalid range; nothing to do.
        return;
    }

    // Initialize the histogram on the device to zero so that the kernel
    // can safely accumulate into it with atomicAdd.
    const size_t histBytes = static_cast<size_t>(range) * sizeof(unsigned int);
    cudaMemset(histogram, 0, histBytes);

    // Choose a reasonable block size for modern GPUs.
    const int threadsPerBlock = 256;

    // Compute a grid size that provides enough parallelism.
    // Use a grid-stride loop in the kernel to handle remaining data.
    unsigned int blocksPerGrid;
    if (inputSize == 0) {
        blocksPerGrid = 1;  // Launch a minimal grid; kernel will do no work.
    } else {
        blocksPerGrid = (inputSize + threadsPerBlock - 1) / threadsPerBlock;
        const unsigned int maxBlocks = 65535u;  // Conservative cap for 1D grids.
        if (blocksPerGrid > maxBlocks) {
            blocksPerGrid = maxBlocks;
        }
    }

    // Shared memory size per block: one unsigned int per bin.
    const size_t sharedMemBytes = static_cast<size_t>(range) * sizeof(unsigned int);

    // Launch kernel. The caller is responsible for any needed synchronization.
    histogram_kernel<<<blocksPerGrid, threadsPerBlock, sharedMemBytes>>>(
        input, histogram, inputSize, from, to);
}

#include <cuda_runtime.h>

/*
 * CUDA kernel that computes a histogram for characters in the range [from, from + numBins - 1].
 *
 * Parameters:
 *   input     - pointer to device memory with 'inputSize' bytes of text
 *   hist      - pointer to device memory with 'numBins' unsigned int bins
 *   inputSize - number of bytes in 'input'
 *   from      - starting character code (inclusive)
 *   numBins   - number of histogram bins = (to - from + 1)
 *
 * Each block builds a partial histogram in shared memory, then atomically
 * accumulates it into the global histogram. A grid-stride loop is used so
 * the kernel can handle arbitrarily large inputs with a fixed launch size.
 */
__global__ void histogram_range_kernel(const char * __restrict__ input,
                                       unsigned int * __restrict__ hist,
                                       unsigned int inputSize,
                                       int from,
                                       int numBins)
{
    // Shared-memory histogram for this block. We allocate the maximum possible
    // number of bins (256) and only use the first 'numBins' entries.
    __shared__ unsigned int s_hist[256];

    // Zero out the shared histogram cooperatively.
    for (int i = threadIdx.x; i < numBins; i += blockDim.x) {
        s_hist[i] = 0;
    }
    __syncthreads();

    const unsigned int globalThreadId =
        blockIdx.x * blockDim.x + threadIdx.x;
    const unsigned int totalThreads =
        gridDim.x * blockDim.x;

    // Grid-stride loop over the input.
    for (unsigned int idx = globalThreadId; idx < inputSize; idx += totalThreads) {
        unsigned char c = static_cast<unsigned char>(input[idx]);
        int bin = static_cast<int>(c) - from;

        // Only count characters that fall into the requested range.
        if (bin >= 0 && bin < numBins) {
            // Shared-memory atomics are fast on modern GPUs and drastically
            // reduce global-memory contention compared to direct global atomics.
            atomicAdd(&s_hist[bin], 1u);
        }
    }
    __syncthreads();

    // Accumulate the per-block histogram into the global histogram.
    for (int i = threadIdx.x; i < numBins; i += blockDim.x) {
        unsigned int count = s_hist[i];
        if (count > 0) {
            atomicAdd(&hist[i], count);
        }
    }
}

/*
 * Host-side helper that sets up and launches the histogram kernel.
 *
 * Parameters:
 *   input      - device pointer to input text (allocated with cudaMalloc)
 *   histogram  - device pointer to output histogram array with
 *                (to - from + 1) unsigned int entries (allocated with cudaMalloc)
 *   inputSize  - number of characters in 'input'
 *   from, to   - character range [from, to] (0 <= from <= to <= 255)
 *
 * The function:
 *   1. Zeros the histogram buffer on the device.
 *   2. Configures a reasonable grid/block size.
 *   3. Launches the CUDA kernel.
 *
 * Synchronization and error checking are left to the caller, as requested.
 */
void run_histogram(const char *input,
                   unsigned int *histogram,
                   unsigned int inputSize,
                   int from,
                   int to)
{
    // Number of histogram bins to compute.
    const int numBins = to - from + 1;

    if (numBins <= 0) {
        // Nothing to do; invalid range or empty.
        return;
    }

    // Initialize the device histogram to zero. This is asynchronous
    // with respect to the host but ordered within the default stream.
    cudaMemset(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int));

    // If there is no input data, we are done after zeroing the histogram.
    if (inputSize == 0) {
        return;
    }

    // Choose a block size that gives good occupancy on modern GPUs.
    const int blockSize = 256;

    // Choose grid size based on input size, but cap it to avoid extremely
    // large grids. 65535 is the legacy maximum for gridDim.x and is still
    // a reasonable upper bound even on modern hardware.
    int gridSize = static_cast<int>((inputSize + blockSize - 1u) / blockSize);
    const int maxGridSize = 65535;
    if (gridSize > maxGridSize) {
        gridSize = maxGridSize;
    }
    if (gridSize < 1) {
        gridSize = 1;
    }

    // Launch the kernel. No explicit synchronization or error checking
    // is performed here, as per the problem statement.
    histogram_range_kernel<<<gridSize, blockSize>>>(input,
                                                    histogram,
                                                    inputSize,
                                                    from,
                                                    numBins);
}

#include <cuda_runtime.h>

/*
 * CUDA kernel to compute a histogram over a specified inclusive character range [from, to].
 *
 * Parameters:
 *   input      - device pointer to input characters
 *   histogram  - device pointer to global histogram array of size (to - from + 1)
 *   inputSize  - number of characters in input
 *   from, to   - inclusive character range [from, to] to be histogrammed
 *
 * Strategy:
 *   - Each block maintains a private histogram in shared memory to reduce global atomic contention.
 *   - Threads cooperatively initialize the shared histogram.
 *   - Threads process input using a grid-stride loop and update shared histogram with atomics.
 *   - After processing, threads cooperatively accumulate the shared histogram into the global histogram.
 */
__global__ void histogram_kernel(const char * __restrict__ input,
                                 unsigned int * __restrict__ histogram,
                                 unsigned int inputSize,
                                 int from,
                                 int to)
{
    extern __shared__ unsigned int s_hist[];

    const int numBins = to - from + 1;
    const bool fullRange = (from == 0) && (to == 255);

    // Initialize shared histogram to zero
    for (int i = threadIdx.x; i < numBins; i += blockDim.x) {
        s_hist[i] = 0;
    }
    __syncthreads();

    // Compute global thread index and stride using 64-bit to avoid overflow
    size_t tid    = static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
    size_t stride = static_cast<size_t>(blockDim.x) * gridDim.x;

    // Grid-stride loop over input
    for (size_t i = tid; i < static_cast<size_t>(inputSize); i += stride) {
        unsigned char c = static_cast<unsigned char>(input[i]);
        int code = static_cast<int>(c);

        if (fullRange) {
            // Fast path for full 0-255 range: no range check needed
            atomicAdd(&s_hist[code], 1U);
        } else {
            // General case: only count characters in [from, to]
            if (code >= from && code <= to) {
                int idx = code - from;  // bin index in [0, numBins-1]
                atomicAdd(&s_hist[idx], 1U);
            }
        }
    }

    __syncthreads();

    // Accumulate per-block shared histogram into global histogram
    for (int i = threadIdx.x; i < numBins; i += blockDim.x) {
        unsigned int val = s_hist[i];
        if (val > 0) {
