    __syncthreads();

    // Merge the per-block shared histogram into the global histogram.
    // Again, threads cooperate so each thread handles a subset of bins.
    for (int i = threadIdx.x; i < numBins; i += blockDim.x) {
        unsigned int val = shared_hist[i];
