    const int numBins = to - from + 1;

    // Handle trivial cases early
    if (numBins <= 0 || inputSize == 0) {
        return;
    }

    // Zero the histogram buffer on the device
    cudaMemset(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int));

