    // Each thread is responsible for a strided subset of bins.
    for (int bin = tid; bin < range; bin += nThreads) {
        unsigned int sum = 0;
        // Sum across all copies.
        for (int copy = 0; copy < histCopies; ++copy) {
            sum += sharedHist[copy * rowStride + bin];
