        if (static_cast<unsigned int>(bin) < static_cast<unsigned int>(numBins)) {
            // Multiple warps share the same per-lane histogram copy, so
            // shared-memory atomics are necessary for correctness.
            atomicAdd(&myHist[bin], 1u);
