    const int numBins = to - from + 1;

    // For safety, handle empty input: just zero the histogram and return.
    if (inputSize == 0)
    {
        cudaMemsetAsync(histogram, 0, static_cast<size_t>(numBins) * sizeof(unsigned int), 0);
