    }

    // Stride for per-lane histograms in shared memory:
    //  - At least numBins.
    //  - Must be odd to ensure gcd(stride, 32) == 1 and thus avoid bank conflicts.
    int stride = numBins;
    if ((stride & 1) == 0)  // if even, make it odd
