    unsigned int blocks =
        (inputSize + blockSize * itemsPerThread - 1) / (blockSize * itemsPerThread);
    if (blocks == 0) {
        blocks = 1;
    }

    // Shared memory size: 32 copies of the histogram, each with numBins entries.
    const size_t sharedMemSize =
